{
  CURL *curl = NULL;
  CURLcode res = CURLE_OK;

  curl = curl_easy_init();
  fail_unless(curl != NULL, "curl_easy_init() failed");

  /* Test setting H3_STREAM_PRIORITY with urgency only */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=5");
  fail_unless(res == CURLE_OK, "curl_easy_setopt(CURLOPT_H3_STREAM_PRIORITY, 'u=5') failed");

  /* Test setting H3_STREAM_PRIORITY with urgency and incremental flag */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=3,i");
  fail_unless(res == CURLE_OK, "curl_easy_setopt(CURLOPT_H3_STREAM_PRIORITY, 'u=3,i') failed");

  /* Test setting with different urgency values */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=0");
  fail_unless(res == CURLE_OK, "curl_easy_setopt(CURLOPT_H3_STREAM_PRIORITY, 'u=0') failed");

  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=7");
  fail_unless(res == CURLE_OK, "curl_easy_setopt(CURLOPT_H3_STREAM_PRIORITY, 'u=7') failed");

  /* Test setting with NULL to clear */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, NULL);
  fail_unless(res == CURLE_OK, "curl_easy_setopt(CURLOPT_H3_STREAM_PRIORITY, NULL) failed");

  curl_easy_cleanup(curl);
}
UNITTEST_STOP

